const token = $input.first().json.headers['x-admin-token'];
if (!token) return [{json: {ok: 'false', error: 'No autorizado'}}];
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  const parts = decoded.split('|');
  if (parts.length !== 3 || parts[2] !== 'CrackTesos2026_Admin_Token') {
    return [{json: {ok: 'false', error: 'Token inválido'}}];
  }
  const tokenAge = Date.now() - parseInt(parts[1]);
  if (tokenAge > 8 * 3600 * 1000) return [{json: {ok: 'false', error: 'Sesión expirada'}}];
} catch(e) {
  return [{json: {ok: 'false', error: 'Token inválido'}}];
}
const body = $input.first().json.body;
if (!body.trivia_id || !body.trivia_number || !body.eligible_users?.length) {
  return [{json: {ok: 'false', error: 'Datos incompletos'}}];
}
return [{json: {
  ok: 'true',
  trivia_id: body.trivia_id,
  trivia_number: body.trivia_number,
  eligible_users: body.eligible_users,
  operator_email: body.operator_email || 'unknown',
  source_file: body.source_file || 'upload'
}}];

const validated = $('Validar').first().json;

const batchId = crypto.randomUUID();

const users = validated.eligible_users.filter(u => !u.already_applied && u.multiplier > 0);

if (users.length === 0) {
  return [{json: {ok: 'false', error: 'Todos los usuarios ya tienen el multiplicador aplicado'}}];
}

const totalGoalsAdded = users.reduce((s, u) => s + u.goals_to_add, 0);

const batchInsert = `INSERT INTO ct_multiplier_batches (batch_id, trivia_id, trivia_number, source_file, total_records_file, eligible_records, applied_records, total_goals_added, status, applied_at, applied_by, ip_address) VALUES ('${batchId}', '${validated.trivia_id}', ${validated.trivia_number}, '${validated.source_file}', ${users.length}, ${users.length}, ${users.length}, ${totalGoalsAdded}, 'applied', NOW() AT TIME ZONE 'America/Bogota', '${validated.operator_email}', 'web-module');`;

const ledgerValues = users.map(u =>
  `('${u.user_id}', '${validated.trivia_id}', ${validated.trivia_number}, 'multiplier_bonus', ${u.goals_to_add}, '+${u.goals_to_add} goles por ${u.number_of_codes} códigos — Trivia #${validated.trivia_number}', '${batchId}', 'admin:${validated.operator_email}')`
).join(',');
const ledgerInsert = `INSERT INTO ct_scoring_ledger (user_id, trivia_id, trivia_number, movement_type, amount, description, reference_id, created_by) VALUES ${ledgerValues};`;

const responseUpdates = users.map(u =>
  `UPDATE ct_trivia_responses SET multiplier_bonus = ${u.goals_to_add}, final_goals = ${u.goals_final} WHERE response_id = '${u.response_id}';`
).join(' ');

const userUpdates = users.map(u =>
  `UPDATE ct_users SET total_goals = total_goals + ${u.goals_to_add}, updated_at = NOW() WHERE user_id = '${u.user_id}';`
).join(' ');

const auditInsert = `INSERT INTO ct_audit_logs (event_type, operator_email, trivia_number, user_affected, payload, result, ip_address) VALUES ('multiplier_applied', '${validated.operator_email}', ${validated.trivia_number}, 'bulk:${users.length}', '{"batch_id": "${batchId}", "total_goals_added": ${totalGoalsAdded}}'::jsonb, 'success', 'web-module');`;

const fullSql = `${batchInsert} ${ledgerInsert} ${responseUpdates} ${userUpdates} ${auditInsert} SELECT 1 AS done;`;

return [{json: {
  ok: 'true',
  batch_id: batchId,
  trivia_id: validated.trivia_id,
  trivia_number: validated.trivia_number,
  operator_email: validated.operator_email,
  users_count: users.length,
  total_goals_added: totalGoalsAdded,
  fullSql
}}];
